(function(){"use strict";const e=document.getElementById("contact-form");if(!e)return;const n=document.getElementById("submit-btn"),s=n.querySelector(".btn-text"),o=n.querySelector(".btn-loading"),t=document.getElementById("form-status");e.addEventListener("submit",async function(i){i.preventDefault(),s.style.display="none",o.style.display="inline",n.disabled=!0,t.textContent="",t.className="form-status";try{const s=new FormData(e),o=await fetch("https://api.web3forms.com/submit",{method:"POST",body:s}),n=await o.json();if(n.success)t.textContent=e.dataset.success||"Request sent successfully!",t.classList.add("success"),e.reset();else throw new Error(n.message||"Submission failed")}catch{t.textContent=e.dataset.error||"Error sending. Please try again.",t.classList.add("error")}finally{s.style.display="inline",o.style.display="none",n.disabled=!1}});const i=document.getElementById("phone");i&&i.addEventListener("input",function(){let e=this.value.replace(/[^\d+\-\s()]/g,"");this.value=e})})()